{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-to-Recipient relationship to a 1:N relationship. This is a fundamental structural change to a core aggregate, affecting the entire bounded context of shipment fulfillment, downstream integrations, and 2 million rows of production data.",
    "bounded_context": "Shipment Fulfillment / Delivery Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of work representing the transportation of goods from origin to one or more delivery points. The aggregate root." },
      { "term": "Recipient", "definition": "A party designated to receive goods at a specific address, with contact details and delivery preferences. Now a child entity within the Shipment aggregate rather than a value object embedded directly." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how delivery should be attempted — e.g., safe place authorization, time windows, signature requirements, alternative contact." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a shipment. Critical for backward compatibility — legacy shipments always have exactly one, which is the primary." },
      { "term": "Delivery Attempt", "definition": "A single try to deliver goods to a specific Recipient at their address. In the new model, attempts must be scoped to a Recipient, not just a Shipment." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a shipment. In a multi-recipient model, aggregate status must now be derived from the statuses of all individual recipient deliveries." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in the current single-recipient format. These represent a bounded context boundary with its own contract." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery destination and is physically undeliverable. This is a data integrity constraint — a recipientless shipment is corrupt state.",
      "testable_assertion": "shipment.recipients.length >= 1 must hold true at every state transition of the Shipment aggregate."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment MUST have a name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These three fields are the minimum required to attempt a delivery and contact the recipient on failure. Without any one, the courier cannot fulfill the delivery.",
      "testable_assertion": "For every recipient R in shipment.recipients: R.name is non-empty, R.address is a valid deliverable address, R.phone is a valid contactable number."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment MUST have a unique address. A shipment cannot have two recipients at the same address.",
      "invariant": false,
      "invariant_justification": "This is a business policy to prevent duplicate deliveries and operational confusion. A VP could decide to allow same-address multi-recipient scenarios (e.g., different departments in a building), but by default it should be enforced.",
      "testable_assertion": "No two recipients in shipment.recipients share the same normalized address."
    },
    {
      "id": "BR-4",
      "rule": "Delivery Preferences are optional per Recipient and default to the platform standard if not specified.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy layer, not a data integrity requirement. Defaults can change.",
      "testable_assertion": "A Recipient with no explicit delivery preferences is assigned platform-default preferences at delivery planning time."
    },
    {
      "id": "BR-5",
      "rule": "Shipment aggregate status must be derived from individual Recipient delivery statuses. A Shipment is 'Delivered' only when ALL Recipients have received their delivery.",
      "invariant": true,
      "invariant_justification": "If any recipient has not received their goods, the shipment is not complete. Reporting it as delivered would be a data integrity violation and would misrepresent fulfillment to the sender.",
      "testable_assertion": "shipment.status == 'Delivered' if and only if every recipient in shipment.recipients has status 'Delivered'."
    },
    {
      "id": "BR-6",
      "rule": "All existing single-recipient shipments must remain valid and queryable with no data loss or behavioral change after migration.",
      "invariant": true,
      "invariant_justification": "2 million production records represent real contractual obligations. Corrupting or losing them violates data integrity and potentially legal requirements.",
      "testable_assertion": "After migration, every pre-existing shipment has exactly one Recipient with name, address, and phone matching its original values."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in a compatible format during and after migration.",
      "invariant": false,
      "invariant_justification": "This is a contractual/integration policy. Partners could be migrated to a new API version, but breaking them without notice would violate SLAs. This is a policy constraint, not a physical or state-integrity one.",
      "testable_assertion": "Partner API payloads for single-recipient shipments remain structurally identical to pre-migration format. Multi-recipient shipments sent to legacy partner endpoints include only the primary recipient."
    },
    {
      "id": "BR-8",
      "rule": "A Shipment that is already in-transit or delivered cannot have Recipients added or removed.",
      "invariant": true,
      "invariant_justification": "Once goods are physically in motion or delivered, changing the recipient list would create a mismatch between physical reality and system state. This is a state integrity constraint.",
      "testable_assertion": "Attempting to add or remove a Recipient on a Shipment with status in ['InTransit', 'Delivered', 'Cancelled'] throws an invariant violation error."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "the creator specifies multiple Recipients with valid name, address, phone, and optional delivery preferences",
      "then": "the Shipment is created with all Recipients as child entities, each with their own delivery status initialized to 'Pending'"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "the creator provides zero Recipients",
      "then": "creation is rejected with a validation error enforcing BR-1"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "it is queried via the API",
      "then": "it returns the original recipient data under a recipients collection with exactly one entry, and all original fields are preserved"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment where 2 of 3 Recipients have been delivered",
      "when": "the Shipment status is queried",
      "then": "the aggregate status is 'PartiallyDelivered' (or equivalent), NOT 'Delivered'"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment",
      "when": "data is sent to a legacy partner API that expects single-recipient format",
      "then": "the primary recipient is sent in the legacy field structure, and no breaking schema changes are introduced"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with status 'InTransit'",
      "when": "a request is made to add a new Recipient",
      "then": "the request is rejected with an error citing the immutability of recipients on in-transit shipments"
    },
    {
      "id": "AC-7",
      "given": "A Recipient on a Shipment has delivery preferences specifying 'no safe place, signature required'",
      "when": "a delivery attempt is made",
      "then": "the courier system enforces that specific Recipient's preferences, independent of other Recipients on the same Shipment"
    },
    {
      "id": "AC-8",
      "given": "The data migration is run against 2 million existing shipments",
      "when": "migration completes",
      "then": "every shipment has exactly one Recipient entity, all original data is preserved, and no shipment is left in an invalid state"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where one Recipient's delivery fails permanently (e.g., address unreachable) but others succeed.",
      "expected_behavior": "The Shipment status reflects partial failure. The sender is notified of the specific failed Recipient. The Shipment cannot be marked 'Delivered'. A return or re-route workflow is triggered for the failed Recipient only."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery preferences (e.g., one requires morning delivery, another requires evening).",
      "expected_behavior": "Each Recipient's preferences are honored independently. Route optimization must treat them as separate delivery stops. This may affect shipping cost and SLA calculations."
    },
    {
      "scenario": "A partner API receives a webhook for a multi-recipient Shipment event but only understands single-recipient format.",
      "expected_behavior": "The anti-corruption layer translates to single-recipient format using the primary recipient. A new API version is offered for partners who want multi-recipient data. No silent data loss — if important per-recipient events occur, they are queued for partners on the new API version."
    },
    {
      "scenario": "A Recipient is removed from a Shipment that is still in 'Created' status, leaving zero Recipients.",
      "expected_behavior": "The removal is rejected. BR-1 (minimum one Recipient) is enforced. The system does not allow the last Recipient to be removed."
    },
    {
      "scenario": "Migration is interrupted halfway through the 2 million records.",
      "expected_behavior": "Migration must be idempotent and resumable. Already-migrated records are not re-processed. Un-migrated records continue to work under the old schema via backward-compatible read paths."
    },
    {
      "scenario": "A Shipment has 50+ Recipients.",
      "expected_behavior": "The system should enforce a reasonable upper bound on recipient count. Without a limit, route planning, status tracking, and notification systems could degrade. The bound is a business policy (BR, not invariant) — suggest a configurable max, e.g., 20."
    },
    {
      "scenario": "Billing and invoicing: a multi-recipient shipment — is it one charge or per-recipient?",
      "expected_behavior": "This is unspecified in the current requirement and must be resolved before implementation. The pricing model fundamentally changes if each recipient is a separate delivery stop with separate SLA."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments may increase average order value but also increase delivery cost per shipment (multiple stops). Pricing model must be revisited — charging flat per-shipment underprices multi-stop routes. Migration itself carries cost: engineering time, testing, partner communication. Risk of billing errors during transition if pricing logic isn't updated atomically with the model change.",
    "operational": "Route optimization algorithms must be updated to handle N stops per shipment. Courier workload estimation changes. Status tracking dashboards need per-recipient granularity. Customer support must handle partial-delivery scenarios. SLA definitions become more complex — is the SLA per-recipient or per-shipment?",
    "user": "Senders gain flexibility to ship to multiple recipients in one operation. Recipients gain personalized delivery preferences. However, tracking becomes more complex for senders — they need visibility into per-recipient status. Notification systems must be updated to send per-recipient updates rather than per-shipment.",
    "risk": "HIGH. This is a change to a core aggregate boundary. Risks include: (1) data migration failure on 2M records, (2) partner API breakage causing SLA violations, (3) billing model mismatch causing revenue leakage, (4) status derivation bugs causing false 'Delivered' signals, (5) performance degradation on hot paths that assumed 1:1 relationship. The change touches nearly every downstream system.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "New capability to address multiple recipients per shipment. Must update their integration if using API. UI workflows change." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. Tracking experience is isolated to their specific delivery within the shipment." },
      { "group": "Couriers/Drivers", "impact": "Route planning changes. A single shipment now means potentially multiple stops. Workload and compensation models may need adjustment." },
      { "group": "External Partners", "impact": "API contract changes. Legacy partners need an anti-corruption layer. New API version must be offered. Communication and migration timeline required." },
      { "group": "Customer Support", "impact": "Must handle new scenarios: partial delivery, per-recipient failures, split statuses. Training and tooling updates needed." },
      { "group": "Finance/Billing", "impact": "Pricing model must account for multi-stop shipments. Invoice format changes. Revenue recognition may be affected if delivery is partial." },
      { "group": "Engineering/Platform", "impact": "Schema migration on 2M records. All query paths, reports, and analytics that assume 1:1 must be audited. Performance testing required for N+1 query risks." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically incomplete. It says 'one or more Recipients' and 'different delivery preferences' but does not define: (1) what delivery preferences consist of, (2) how pricing works for multi-recipient shipments, (3) what the aggregate status lifecycle looks like, (4) whether there is a recipient cap, (5) SLA implications. The partner API backward-compatibility requirement is implicit, not specified. Multiple unresolved business questions remain that could change the shape of the solution.",
    "high_confidence_areas": [
      "The 1:N structural change from embedded value object to child entity collection is the correct modeling direction",
      "BR-1 (minimum one recipient) is a hard invariant",
      "BR-6 (migration must preserve all existing data) is non-negotiable",
      "Partner API backward compatibility is required"
    ],
    "low_confidence_areas": [
      "Delivery preferences schema — completely undefined in the spec",
      "Pricing and billing model for multi-recipient shipments",
      "Aggregate status lifecycle and what states exist (e.g., PartiallyDelivered)",
      "Maximum recipient count per shipment",
      "SLA definition — per-shipment or per-recipient",
      "Whether same-address multi-recipient is a valid business scenario"
    ],
    "assumptions": [
      "Delivery preferences include at minimum: time window, safe place authorization, signature requirement, and alternative contact",
      "The first recipient or an explicitly designated recipient serves as 'primary' for backward compatibility",
      "Partner APIs have contractual SLAs that prevent unilateral breaking changes",
      "Migration can be performed online (no downtime) given the 2M record volume",
      "Existing shipment tracking numbers and external identifiers remain stable through migration"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'delivery preferences' consist of. This is a first-class domain concept that directly shapes the Recipient entity schema, courier workflows, and UI. Without a defined preference schema, acceptance criteria for AC-7 cannot be fully validated.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Engineering/Platform"],
      "options": ["Define a minimal preference set (time window, signature, safe place) and iterate", "Conduct stakeholder interviews to capture full preference taxonomy before implementation"],
      "recommendation": "Define a minimal viable preference set now, flag it as extensible, and validate with operations and courier teams before finalizing."
    },
    {
      "type": "ambiguity",
      "description": "Pricing model for multi-recipient shipments is unspecified. A multi-recipient shipment is fundamentally multiple delivery stops. Charging a single-shipment rate causes revenue leakage; charging per-recipient may deter adoption. This must be a deliberate business decision, not an engineering default.",
      "affected_stakeholders": ["Finance/Billing", "Senders/Shippers", "Product"],
      "options": ["Per-shipment flat rate (simple, but underprices)", "Base rate + per-additional-recipient surcharge", "Per-recipient pricing (transparent, may reduce adoption)"],
      "recommendation": "Base rate + per-additional-recipient surcharge balances revenue protection with adoption incentives. Finance must sign off."
    },
    {
      "type": "missing_context",
      "description": "The aggregate Shipment status lifecycle for multi-recipient scenarios is undefined. Current statuses (Created, InTransit, Delivered, etc.) assume a single delivery outcome. Multi-recipient requires new states like 'PartiallyDelivered' and 'PartiallyFailed', plus rules for state transitions.",
      "affected_stakeholders": ["Customer Support", "Senders/Shippers", "Engineering/Platform"],
      "options": ["Extend current status enum with partial states", "Introduce a two-level status model: shipment-level (derived) and recipient-level (authoritative)"],
      "recommendation": "Two-level status model. Recipient-level status is authoritative; shipment-level is derived. This is cleaner and avoids combinatorial explosion of aggregate states."
    },
    {
      "type": "missing_context",
      "description": "Partner API versioning and migration strategy is not specified. How many partners exist? What are their SLA terms? What is the timeline for deprecating the single-recipient API format? Without this, BR-7 cannot be fully specified.",
      "affected_stakeholders": ["External Partners", "Engineering/Platform"],
      "options": ["Maintain v1 indefinitely with anti-corruption layer", "Announce v2, give partners 6-12 month migration window, then deprecate v1"],
      "recommendation": "Maintain v1 via anti-corruption layer with no deprecation date initially. Offer v2 for partners who want multi-recipient data. Set deprecation timeline after partner adoption reaches threshold."
    }
  ],

  "rejection_reasons": []
}

